function toNum(x) {
  if (x === null || x === undefined) return 0;
  if (typeof x === 'number') return isFinite(x) ? x : 0;
  if (typeof x === 'string') { var n = parseFloat(x); return isFinite(n) ? n : 0; }
  return 0;
}

// ===========================================================================
// VMR0015 v1.0 (Verra revision to CDM AMS-III.AV) - Safe Drinking Water dMRV
// Baseline equation per AMS-III.AV (UNFCCC CDM), Equations (1),(5),(7):
//
//   SEC  = 357.48 / nwb                                  (kJ/L)  [Eq.5]
//   BE_y = QPW_y * m * X_boil * SEC
//                 * (BL_fuel * f_i * EF_fuel * 1e-9)      (tCO2e) [Eq.1]
//   ER_y = BE_y - PE_y - LE_y                             (tCO2e) [Eq.7]
//
// Monitoring Report schema #31d7ef1c (FLAT):
//   field3  = BE Total (tCO2e)        <- COMPUTED here
//   field4  = PE Total (tCO2e)        (TOOL03 + TOOL05, entered)
//   field5  = LE Total (tCO2e)        (AMS-I.E. leakage, entered)
//   field6  = ER Total (tCO2e)        <- minted amount, computed here
//   field10 = Appliances passing water-quality requirement (count)
//   field11 = Appliances total (count)
//   field12 = QPW_y purified water (L/yr)
//   field13 = m  fraction of functional appliances meeting SDW (0-1)
//   field14 = X_boil fraction of population whose baseline is boiling (0-1)
//   field15 = nwb efficiency of replaced water-boiling system (0-1)
//   field16 = EF_fuel emission factor of substituted fuel (tCO2/TJ)
//   field17 = f_i non-renewable fraction of baseline fuel (0-1, fNRB; =1 fossil)
//   field18 = BL_fuel proportion of baseline fuel type i (0-1)
// ===========================================================================

// AMS-III.AV water-quality gate. The methodology states emission reductions
// CANNOT be claimed if OVER 10% of appliances fail the water-quality
// requirement -> i.e. the project must keep >= 90% of appliances passing.
// Fail-closed: missing/zero appliance data => treated as failing => no credits.
function appliance_pass_rate(raw) {
  var passing = toNum(raw.field10);
  var total   = toNum(raw.field11);
  if (total <= 0) return 0;            // no evidence -> fail closed
  if (passing < 0) passing = 0;
  if (passing > total) passing = total;
  return passing / total;
}

// Specific energy consumption to boil 1 L of water (AMS-III.AV Eq.5):
//   SEC = 357.48 / nwb   (kJ/L)
// 357.48 = WH*(Tf-Ti) + 0.01*WHE = 4.186*(100-20) + 0.01*2260.
function compute_SEC(nwb) {
  if (nwb <= 0) return 0;              // invalid efficiency -> no baseline
  return 357.48 / nwb;
}

// Baseline emissions per AMS-III.AV Eq.1 (single baseline fuel type).
function compute_baseline_emissions(raw) {
  var QPW   = toNum(raw.field12);      // L/yr
  var m     = toNum(raw.field13);      // 0-1
  var Xboil = toNum(raw.field14);      // 0-1
  var nwb   = toNum(raw.field15);      // 0-1
  var EF    = toNum(raw.field16);      // tCO2/TJ
  var fi    = toNum(raw.field17);      // 0-1
  var BLf   = toNum(raw.field18);      // 0-1
  // clamp fractions to [0,1]
  if (m < 0) m = 0; if (m > 1) m = 1;
  if (Xboil < 0) Xboil = 0; if (Xboil > 1) Xboil = 1;
  if (fi < 0) fi = 0; if (fi > 1) fi = 1;
  if (BLf < 0) BLf = 0; if (BLf > 1) BLf = 1;
  var SEC = compute_SEC(nwb);          // kJ/L
  // BE (tCO2e) = QPW(L) * m * Xboil * SEC(kJ/L) * BLfuel * fi * EF(tCO2/TJ) * 1e-9 (TJ/kJ)
  var be = QPW * m * Xboil * SEC * (BLf * fi * EF * 1e-9);
  if (be < 0) be = 0;
  return be;
}

function calc_vmr0015(doc) {
  var subj = doc.credentialSubject;
  var raw  = (subj && subj.length) ? subj[0] : doc;

  // --- BE computed from monitored parameters (AMS-III.AV Eq.1 & 5) ---
  var BE_total = compute_baseline_emissions(raw);
  raw.field3 = Math.round(BE_total * 100) / 100;   // write back computed BE

  var PE_total = toNum(raw.field4);
  var LE_total = toNum(raw.field5);

  // --- ER = BE - PE - LE (AMS-III.AV Eq.7) ---
  var ER_total = BE_total - PE_total - LE_total;
  if (ER_total < 0) ER_total = 0;

  // --- Water-quality hard gate: block if >10% appliances fail (>=90% pass) ---
  var pass_rate = appliance_pass_rate(raw);
  if (pass_rate < 0.90) {
    ER_total = 0;   // AMS-III.AV: ERs cannot be claimed -> no credits
  }

  // Write ER_y to the schema-defined mint slot (field6).
  raw.field6 = Math.round(ER_total * 100) / 100;

  return doc;
}

